		function LoadMdx()
{                             
  proxy = GetProxy();

  qry = proxy.FileServiceIO().LoadTXTFile("TEMP", "query.mdx");

  mdx = qry.substring(qry.indexOf("<mdx>")+5, qry.indexOf("</mdx>"))

  mdx = clearMdx(mdx);                
  mdx =Trim(mdx);

	Ctrl("mdx").SetXValue(mdx);

	return true;
}


function clearMdx(txt) 
{              
	var mdx = "";

  txt = Replace(txt, "\n", " ");
  txt = Replace(txt, "\r", "");


	for(i=0; i<txt.length; i++) 
	{
		if(txt.charCodeAt(i) >= 32 && txt.charCodeAt(i) <= 254) 		
		{                     
			if(txt.charCodeAt(i) >= 127 && txt.charCodeAt(i) <= 132) continue;
			if(txt.charCodeAt(i) >= 134 && txt.charCodeAt(i) <= 160) continue;
			mdx += txt.charAt(i);
		}
  }    
  mdx =Trim(mdx);

	return mdx;
}
